# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
from google.cloud import storage

def convert_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    metadata = blob.metadata or {}
    
    temp_input_path = f'/tmp/{os.path.basename(file_name)}'
    blob.download_to_filename(temp_input_path)
    
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', None)
    quality = metadata.get('quality', None)
    rotate = metadata.get('rotate', None)
    grayscale = metadata.get('grayscale', 'false').lower() == 'true'
    blur = metadata.get('blur', None)
    crop = metadata.get('crop', None)
    flip = metadata.get('flip', None)
    flop = metadata.get('flop', 'false').lower() == 'true'
    brightness = metadata.get('brightness', None)
    contrast = metadata.get('contrast', None)
    sharpen = metadata.get('sharpen', None)
    normalize = metadata.get('normalize', 'false').lower() == 'true'
    sepia = metadata.get('sepia', None)
    negate = metadata.get('negate', 'false').lower() == 'true'
    output_bucket = metadata.get('output_bucket', bucket_name)
    output_prefix = metadata.get('output_prefix', 'converted/')
    
    base_name = os.path.splitext(os.path.basename(file_name))[0]
    output_filename = f'{base_name}.{output_format}'
    temp_output_path = f'/tmp/{output_filename}'
    
    convert_command = ['convert', temp_input_path]
    
    if resize:
        convert_command.extend(['-resize', resize])
    
    if quality:
        convert_command.extend(['-quality', quality])
    
    if rotate:
        convert_command.extend(['-rotate', rotate])
    
    if grayscale:
        convert_command.extend(['-colorspace', 'Gray'])
    
    if blur:
        convert_command.extend(['-blur', blur])
    
    if crop:
        convert_command.extend(['-crop', crop])
    
    if flip:
        convert_command.extend(['-flip'])
    
    if flop:
        convert_command.extend(['-flop'])
    
    if brightness:
        convert_command.extend(['-brightness-contrast', f'{brightness}x0'])
    
    if contrast:
        current_brightness = brightness if brightness else '0'
        convert_command = [cmd for cmd in convert_command if cmd != '-brightness-contrast' and not cmd.startswith(current_brightness)]
        convert_command.extend(['-brightness-contrast', f'{brightness or 0}x{contrast}'])
    
    if sharpen:
        convert_command.extend(['-sharpen', sharpen])
    
    if normalize:
        convert_command.extend(['-normalize'])
    
    if sepia:
        convert_command.extend(['-sepia-tone', sepia])
    
    if negate:
        convert_command.extend(['-negate'])
    
    convert_command.append(temp_output_path)
    
    result = subprocess.call(convert_command)
    
    if result == 0:
        output_bucket_obj = storage_client.bucket(output_bucket)
        output_blob_name = f'{output_prefix}{output_filename}'
        output_blob = output_bucket_obj.blob(output_blob_name)
        output_blob.upload_from_filename(temp_output_path)
        
        print(f'Successfully converted {file_name} to {output_blob_name}')
    else:
        print(f'Error converting {file_name}. Return code: {result}')
    
    if os.path.exists(temp_input_path):
        os.remove(temp_input_path)
    if os.path.exists(temp_output_path):
        os.remove(temp_output_path)
    
    return 'OK' if result == 0 else 'ERROR'